example.code:
from contextlib import contextmanager from openai import OpenAI
client = OpenAI()
@contextmanager def managed_vector_store(name: str, file_paths: list[str]): """Upload files, create vector store, yield id, then clean up.""" files = [client.files.create(file=open(p, "rb"), purpose="assistants") for p in file_paths] vs = client.beta.vector_stores.create(name=name) for f in files: client.beta.vector_stores.files.create(vector_store_id=vs.id, file_id=f.id) try: yield vs.id finally: client.beta.vector_stores.delete(vs.id) for f in files: client.files.delete(f.id)
